import React, { useState } from 'react';
import { aiService } from '../services/aiService';

// Page: Proposal Writer
// Collects inputs and asks Claude to generate a full proposal.
const ProposalWriter = () => {
  const [form, setForm] = useState({ clientName: '', company: '', scope: '', budget: '', timeline: '', features: '', yourName: '' });
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleGenerate = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await aiService.callAI('proposal', form);
      setResult(res.data || res);
    } catch (err) {
      console.error(err);
      alert('AI request failed');
    }
    setLoading(false);
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(typeof result === 'string' ? result : JSON.stringify(result));
      alert('Copied to clipboard');
    } catch (err) {
      console.error(err);
      alert('Copy failed');
    }
  };

  return (
    <div>
      <h2>AI Proposal Writer</h2>
      <form onSubmit={handleGenerate}>
        <input name="clientName" placeholder="Client name" value={form.clientName} onChange={handleChange} />
        <input name="company" placeholder="Company" value={form.company} onChange={handleChange} />
        <input name="budget" placeholder="Budget quote" value={form.budget} onChange={handleChange} />
        <input name="timeline" placeholder="Timeline" value={form.timeline} onChange={handleChange} />
        <input name="features" placeholder="Features (comma separated)" value={form.features} onChange={handleChange} />
        <input name="yourName" placeholder="Your name / brand" value={form.yourName} onChange={handleChange} />
        <textarea name="scope" placeholder="Project scope" value={form.scope} onChange={handleChange} />
        <button type="submit" disabled={loading}>{loading ? 'Writing...' : 'Write Proposal'}</button>
      </form>

      {result && (
        <div style={{ marginTop: 20 }}>
          <button onClick={copyToClipboard}>Copy to clipboard</button>
          <pre style={{ whiteSpace: 'pre-wrap' }}>{typeof result === 'string' ? result : JSON.stringify(result, null, 2)}</pre>
        </div>
      )}
    </div>
  );
};

export default ProposalWriter;
